/**
 * Config registration for the pass-through HTTP filter.
 * This filter implements the NamedHttpFilterConfigFactory pattern.
 */
class PassThroughFilterConfig
    : public Extensions::HttpFilters::Common::FactoryBase<google::protobuf::Empty> {
public:
  PassThroughFilterConfig() : FactoryBase("envoy.filters.http.pass_through") {}

private:
  Envoy::Http::FilterFactoryCb createFilterFactoryFromProtoTyped(
      const google::protobuf::Empty& /*proto_config*/, const std::string& /*stats_prefix*/,
      Server::Configuration::FactoryContext& /*context*/) override;
};

} // namespace Http
} // namespace Envoy

#include "config.h"

#include "envoy/registry/registry.h"

#include "pass_through_filter.h"

namespace Envoy {
namespace Http {

Envoy::Http::FilterFactoryCb PassThroughFilterConfig::createFilterFactoryFromProtoTyped(
    const google::protobuf::Empty& /*proto_config*/, const std::string& /*stats_prefix*/,
    Server::Configuration::FactoryContext& /*context*/) {
  return [](Http::FilterChainFactoryCallbacks& callbacks) -> void {
    callbacks.addStreamDecoderFilter(std::make_shared<PassThroughFilter>());
  };
}

/**
 * Static registration for the pass-through HTTP filter.
 * This registers the filter with Envoy's filter factory system using the LEGACY_REGISTER_FACTORY macro.
 */
LEGACY_REGISTER_FACTORY(PassThroughFilterConfig, Server::Configuration::NamedHttpFilterConfigFactory,
                        "envoy.filters.http.pass_through");

} // namespace Http
} // namespace Envoy

